  ('disabled-57f41407-moex-00666', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，非得於法院調解程序中指定調解期日之人？', '["依法院組織法第17條之2規定辦理調解事件之司法事務官", "兩造合意移付調解之訴訟事件審判長", "承辦股書記官", "主任調解委員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00667', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，不適用簡易訴訟程序？', '["請求給付借款利息新臺幣（下同）60萬元", "因建築物定期借貸之保證關係涉訟，請求給付60萬元", "本於合會有所請求而涉訟，請求給付60萬元", "請求給付買賣契約之違約金60萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00668', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲承攬乙委託製作之廣告影片1部，乙拒不付款，甲欲聲請法院發支付命 令。下列敘述何者錯誤？', '["甲須已為對待給付或無對待給付義務始得聲請", "乙如未於法定期間內提出異議，得另行起訴請求確認甲對乙之承攬報酬 請求權不存在", "關於督促程序之管轄，當事人得以合意定之", "法院發支付命令前，毋庸訊問債務人，得逕為裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00669', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲向臺灣臺北地方法院起訴請求乙損害賠償，經該院判決甲敗訴。該判決 送達甲後，書記官發現判決誤載為不得上訴，即處分更正後重新送達判決 與甲，甲收受該更正之判決後，即以掛號郵件方式，寄出上訴狀至臺灣新 北地方法院，臺灣新北地方法院收受該上訴狀後，轉送臺灣臺北地方法院。 有關甲提起第二審上訴期間計算，下列敘述何者正確？', '["應以更正後之判決再為送達與甲之日，重新起算上訴期間", "應以甲交付郵局寄出上訴狀之日，為提起上訴之日", "應以上訴狀到達臺灣新北地方法院之日，為提起上訴之日", "應以上訴狀到達臺灣臺北地方法院之日，為提起上訴之日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00670', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於裁定及其救濟，下列敘述何者錯誤？', '["對於未確定之裁定不服，原則上得為抗告", "裁定得不經言詞辯論為之", "對於已確定之裁定不服，應提起再審之訴", "對於受命法官或受託法官之裁定，不得抗告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00671', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲（原告）與乙（被告）間請求返還借款事件，經第一審、第二審法院分 別駁回甲之起訴及上訴，甲提起第三審上訴，經第三審法院以上訴不合法 為由，裁定駁回其上訴確定。甲欲提起再審之訴，下列敘述何者正確？', '["甲得僅對第一審判決，向第一審法院提起再審之訴", "甲得對第一審及第二審判決，同時向第二審法院提起再審之訴", "甲得對第一審、第二審判決及第三審裁定，同時向第三審法院提起再審 之訴", "甲得僅對第三審裁定，向第三審法院提起再審之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00672', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於再審事由所稱「發現未經斟酌之證物」，下列敘述何者錯誤？', '["不包括前訴訟程序事實審言詞辯論終結前已存在之證據", "該證物必須足以動搖原判決之基礎", "必須因當事人在前訴訟程序不知有此證物，或雖知有此而不能使用者", "不包括證人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00673', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '依督促程序聲請核發支付命令之要件，下列敘述何者錯誤？', '["一定數量之金錢", "一定數量之其他代替物", "一定數量之有價證券", "一定數量之不動產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00674', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於債權人依民法第151條規定聲請押收債務人之財產或拘束其自由，下 列敘述何者錯誤？', '["專屬押收債務人財產或拘束其自由之行為地地方法院管轄", "因拘束債務人自由而為假扣押或假處分之聲請者，法院為准許之裁定， 非命債權人及債務人以言詞為陳述，不得為之", "法院為裁定及開始執行前，應就債務人為適當之處置，但拘束債務人之 自由，自送交法院時起，不得逾36小時", "因拘束債務人之自由而為假扣押或假處分裁定之本案尚未繫屬者，債權 人應於裁定送達後5日內起訴；逾期未起訴時，命假扣押或假處分之法 院得依聲請或依職權撤銷假扣押或假處分裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00675', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'X死亡後，其全體繼承人甲、乙、丙尚未分割遺產。下列訴訟事件，何者 欠缺當事人適格？', '["若丙死亡，其繼承人為A，甲列乙為被告就X之遺產提起遺產分割訴訟", "若乙占有遺產並否認甲之繼承權，甲列乙為被告提起繼承回復請求訴訟", "若丁無權占有遺產，甲列丁為被告提起共有物返還訴訟", "若就丙是否為X之子女一事，甲、丙間有爭執，甲列丙為被告提起確認 X與丙親子關係不存在之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
